import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../utils/api';
import { useCart } from '../context/CartContext';

const Home = () => {
  const [products, setProducts] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [category, setCategory] = useState('All');
  const [sort, setSort] = useState('default');
  const { addToCart } = useCart();

  useEffect(() => {
    api.get('/products')
      .then((res) => { setProducts(res.data); setFiltered(res.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  useEffect(() => {
    let result = [...products];
    if (category !== 'All') result = result.filter(p => p.category === category);
    if (search) result = result.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));
    if (sort === 'low') result.sort((a, b) => a.price - b.price);
    if (sort === 'high') result.sort((a, b) => b.price - a.price);
    if (sort === 'name') result.sort((a, b) => a.name.localeCompare(b.name));
    setFiltered(result);
  }, [search, category, sort, products]);

  const categories = ['All', ...new Set(products.map(p => p.category))];

  const renderStars = (rating) => {
    return '★'.repeat(Math.round(rating)) + '☆'.repeat(5 - Math.round(rating));
  };

  if (loading) return (
    <div style={styles.loadingWrapper}>
      <div style={styles.spinner}></div>
      <p>Loading products...</p>
    </div>
  );

  return (
    <div style={styles.page}>
      {/* Hero Banner */}
      <div style={styles.hero}>
        <h1 style={styles.heroTitle}>🛒 Welcome to MERN Shop</h1>
        <p style={styles.heroSub}>Millions of products. Best prices. Fast delivery.</p>
      </div>

      {/* Search + Filters */}
      <div style={styles.filterBar}>
        <input
          placeholder="🔍 Search products..."
          value={search}
          onChange={e => setSearch(e.target.value)}
          style={styles.searchInput}
        />
        <select value={category} onChange={e => setCategory(e.target.value)} style={styles.select}>
          {categories.map(c => <option key={c}>{c}</option>)}
        </select>
        <select value={sort} onChange={e => setSort(e.target.value)} style={styles.select}>
          <option value="default">Sort: Default</option>
          <option value="low">Price: Low to High</option>
          <option value="high">Price: High to Low</option>
          <option value="name">Name: A-Z</option>
        </select>
      </div>

      {/* Category Pills */}
      <div style={styles.pills}>
        {categories.map(c => (
          <button
            key={c}
            onClick={() => setCategory(c)}
            style={category === c ? styles.pillActive : styles.pill}
          >
            {c}
          </button>
        ))}
      </div>

      {/* Results count */}
      <p style={styles.resultCount}>
        Showing <strong>{filtered.length}</strong> products
        {search && ` for "${search}"`}
        {category !== 'All' && ` in ${category}`}
      </p>

      {/* Product Grid */}
      {filtered.length === 0 ? (
        <div style={styles.empty}>
          <p>😕 No products found.</p>
          <button onClick={() => { setSearch(''); setCategory('All'); }} style={styles.clearBtn}>
            Clear Filters
          </button>
        </div>
      ) : (
        <div style={styles.grid}>
          {filtered.map(p => (
            <div key={p._id} style={styles.card}>
              <Link to={`/product/${p._id}`}>
                <div style={styles.imgWrapper}>
                  <img src={p.image} alt={p.name} style={styles.img} />
                  {p.stock < 10 && p.stock > 0 && (
                    <span style={styles.lowStock}>Only {p.stock} left!</span>
                  )}
                  {p.stock === 0 && (
                    <span style={styles.outOfStock}>Out of Stock</span>
                  )}
                </div>
              </Link>
              <div style={styles.cardBody}>
                <p style={styles.cardCategory}>{p.category}</p>
                <Link to={`/product/${p._id}`} style={styles.cardTitle}>{p.name}</Link>
                <div style={styles.stars}>
                  <span style={styles.starText}>{renderStars(p.rating || 4)}</span>
                  <span style={styles.reviewCount}>({p.numReviews || 0})</span>
                </div>
                <div style={styles.priceRow}>
                  <span style={styles.price}>${p.price}</span>
                  <span style={styles.originalPrice}>${(p.price * 1.2).toFixed(0)}</span>
                  <span style={styles.discount}>17% off</span>
                </div>
                <p style={styles.delivery}>🚚 FREE Delivery</p>
                <button
                  onClick={() => addToCart(p)}
                  disabled={p.stock === 0}
                  style={p.stock === 0 ? styles.disabledBtn : styles.addBtn}
                >
                  {p.stock === 0 ? 'Out of Stock' : '🛒 Add to Cart'}
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

const styles = {
  page: { background: '#f3f3f3', minHeight: '100vh', paddingBottom: '40px' },
  loadingWrapper: { display: 'flex', flexDirection: 'column', alignItems: 'center', marginTop: '100px', gap: '16px' },
  spinner: { width: '40px', height: '40px', border: '4px solid #ddd', borderTop: '4px solid #e94560', borderRadius: '50%', animation: 'spin 0.8s linear infinite' },
  hero: { background: 'linear-gradient(135deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%)', color: '#fff', padding: '60px 24px', textAlign: 'center' },
  heroTitle: { fontSize: '36px', fontWeight: 'bold', margin: '0 0 12px' },
  heroSub: { fontSize: '18px', color: '#ccc', margin: 0 },
  filterBar: { display: 'flex', gap: '12px', padding: '20px 24px', background: '#fff', flexWrap: 'wrap', boxShadow: '0 2px 8px rgba(0,0,0,0.08)' },
